#include <math.h>
#include <omp.h>

#define fp double
#define NUMBER_PAR_PER_BOX 100
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct {
	fp x, y, z;
} THREE_VECTOR;

typedef struct {
	fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str {
	int x, y, z;
	int number;
	long offset;
} nei_str;

typedef struct box_str {
	int x, y, z;
	int number;
	long offset;
	int nn;
	nei_str nei[26];
} box_str;

typedef struct par_str {
	fp alpha;
} par_str;

typedef struct dim_str {
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;
	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;
} dim_str;

void kernel_cpu(par_str par,
                dim_str dim,
                box_str* box,
                FOUR_VECTOR* rv,
                fp* qv,
                FOUR_VECTOR* fv)
{
	const fp a2 = (fp)2.0 * par.alpha * par.alpha;

	if (dim.cores_arg > 0) {
		omp_set_num_threads(dim.cores_arg);
	}

	#pragma omp parallel for schedule(static)
	for (long bx = 0; bx < dim.number_boxes; bx++) {

		int first_i = (int)box[bx].offset;
		FOUR_VECTOR* rA = &rv[first_i];
		FOUR_VECTOR* fA = &fv[first_i];

		FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
		for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
			rA_shared[wtx] = rA[wtx];
		}

		for (int k = 0; k < (1 + box[bx].nn); k++) {

			int pointer = (k == 0) ? (int)bx : box[bx].nei[k - 1].number;
			int first_j = (int)box[pointer].offset;

			FOUR_VECTOR* rB = &rv[first_j];
			fp* qB = &qv[first_j];

			FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
			fp qB_shared[NUMBER_PAR_PER_BOX];

			for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
				rB_shared[wtx] = rB[wtx];
				qB_shared[wtx] = qB[wtx];
			}

			for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
				for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
					fp r2 = (fp)rA_shared[wtx].v + (fp)rB_shared[j].v -
					        DOT((rA_shared[wtx]), (rB_shared[j]));
					fp u2 = a2 * r2;
					fp vij = exp(-u2);
					fp fs = (fp)2.0 * vij;

					THREE_VECTOR d;
					d.x = (fp)rA_shared[wtx].x - (fp)rB_shared[j].x;
					fp fxij = fs * d.x;
					d.y = (fp)rA_shared[wtx].y - (fp)rB_shared[j].y;
					fp fyij = fs * d.y;
					d.z = (fp)rA_shared[wtx].z - (fp)rB_shared[j].z;
					fp fzij = fs * d.z;

					fA[wtx].v += (double)((fp)qB_shared[j] * vij);
					fA[wtx].x += (double)((fp)qB_shared[j] * fxij);
					fA[wtx].y += (double)((fp)qB_shared[j] * fyij);
					fA[wtx].z += (double)((fp)qB_shared[j] * fzij);
				}
			}
		}
	}
}
